mapper.select:
SELECT sr.*, si.code AS item_code, si.name AS item_name, si.unit AS unit,
       u.real_name AS operator_name, lr.reserve_no AS reservation_no
FROM stock_record sr
LEFT JOIN stock_item si      ON si.id = sr.item_id
LEFT JOIN sys_user   u       ON u.id  = sr.user_id
LEFT JOIN lab_reservation lr ON lr.id = sr.reservation_id

  AND sr.item_id = #{itemId}
  AND sr.type    = #{type}
  AND sr.reservation_id = #{reservationId}
  AND sr.user_id = #{userId}

    AND si.lab_id IN

      #{lid}



ORDER BY sr.id DESC

SELECT COALESCE(SUM(sr.qty), 0) FROM stock_record sr LEFT JOIN stock_item si ON si.id = sr.item_id WHERE sr.type = 1
AND si.lab_id IN
#{lid}

SELECT COALESCE(SUM(sr.qty), 0) FROM stock_record sr LEFT JOIN stock_item si ON si.id = sr.item_id WHERE sr.type = 2
AND si.lab_id IN
#{lid}

SELECT sr.item_id AS itemId, si.code AS itemCode, si.name AS itemName, si.unit AS unit, SUM(sr.qty) AS qty FROM stock_record sr LEFT JOIN stock_item si ON si.id = sr.item_id WHERE sr.type = 2
AND si.lab_id IN
#{lid}
GROUP BY sr.item_id, si.code, si.name, si.unit ORDER BY qty DESC LIMIT #{limit}
